import React from "react";
import Navbar from "./Navbar/navbar";
import Footer from "./Footer/Footer";

const Layout = ({ children, isLoading }) => {
  return (
    <div className="layout-container">
      {isLoading && (
        <div className="loading-overlay">
          <Loading />
        </div>
      )}
      <Navbar />
      <main>{children}</main>
      <Footer />
    </div>
  );
};

export default Layout;
